//
// Targeted regeneration of an EXISTING versioned snapshot's GENERATED reference subtree only.
//
// release-cut.mjs refuses to overwrite an existing version (versioned snapshots are immutable by
// design — a version's HAND-AUTHORED content must never silently re-read current source, so there is
// deliberately no "re-cut" mechanism). But the `reference/**` pages under a version are not
// hand-authored at all: every one is 100% generated by generate-references.mjs from the framework's
// own source (JSON schemas, Spring configuration metadata, docs-emitter output), then materialised
// into the snapshot at cut time via dematerialize.mjs — the exact same de-materialisation this script
// reuses. When generate-references.mjs itself has a rendering bug (e.g. a schema definition
// misreported as empty, or a raw Javadoc tag left unstripped), an already-cut snapshot's generated
// pages carry that same bug forever unless something can refresh just that subtree. This script is
// that documented, deterministic mechanism — the version-aware generation path a hand-edit of
// generated MDX would otherwise stand in for.
//
// Scope, deliberately narrow:
//   - Requires `docs/reference/` already regenerated from source (`npm run generate`), exactly like
//     release-stage.mjs's own precondition for a brand-new cut.
//   - Re-uses dematerialize.mjs to resolve every `file=`/`vocab:`/`javadoc:` directive and pin any
//     `/javadoc/next/` route to the target version — so a schema page's already-resolved "## Example"
//     block round-trips to the SAME real content it already had (the fixture files the include role
//     resolves have not changed), never a live, unresolved directive being written into a versioned
//     snapshot.
//   - Overwrites ONLY `versioned_docs/version-<v>/reference/**` — never a hand-authored page in that
//     version, and never any other version's snapshot.
//   - Does NOT itself verify that the framework source generate-references.mjs read from is
//     unchanged since `<v>`'s release tag — that provenance check is the caller's responsibility
//     (e.g. `git diff <tag> HEAD -- <the source paths the generator reads>`), the same trust
//     boundary release-stage.mjs already has for a brand-new cut (it also just trusts `docs/
//     reference/` reflects the right source).
//
// Run via `node scripts/regenerate-versioned-reference.mjs <version>` (after `npm run generate`).
//
// Replacement, not an in-place file-by-file overwrite: every page is generated into a scratch
// staging directory first (a sibling of the version's own `reference/` inside its version
// directory, so the final swap is a same-filesystem rename, not a cross-device copy). Only once
// EVERY page has been generated and de-materialised without error is the existing `reference/`
// subtree removed and the staged one renamed into its place. This is what makes the target mirror
// the current generated inventory exactly (a renamed/deleted generated page cannot leave a stale
// file or an empty stale directory behind) while also failing closed: any generation error leaves
// the original `reference/` subtree completely untouched, never partially replaced.

import {mkdirSync, mkdtempSync, readFileSync, renameSync, rmSync, writeFileSync} from 'node:fs';
import {dirname, join} from 'node:path';
import {dematerialize} from './dematerialize.mjs';
import {loadSets, DEFAULT_VOCAB_DIR} from '../src/remark/vocab.mjs';
import {includeAllowBases, DEFAULT_REPO_ROOT} from '../src/remark/include.mjs';
import {DOCS_DIR, VERSIONED_DOCS, listFiles, pathExists, validateVersion} from './release-paths.mjs';

const STAGING_DIR_PREFIX = '.regenerate-versioned-reference-tmp-';

const REFERENCE_DIR = join(DOCS_DIR, 'reference');

/**
 * Regenerate every file under `versioned_docs/version-<version>/reference/` from the CURRENT
 * `docs/reference/` (already regenerated from source), de-materialised and pinned to `version`.
 *
 * @param {string} version an existing versioned snapshot (e.g. '0.1.0')
 * @param {{referenceDir?: string, versionedDocsDir?: string, vocabDir?: string, repoRoot?: string}} [options]
 *        injectable seams for hermetic tests; production defaults to the real module paths.
 * @returns {number} the number of reference pages written
 */
export function regenerateVersionedReference(version, options = {}) {
  validateVersion(version);
  const referenceDir = options.referenceDir || REFERENCE_DIR;
  const versionedDocsDir = options.versionedDocsDir || VERSIONED_DOCS;
  const vocabDir = options.vocabDir || DEFAULT_VOCAB_DIR;
  const repoRoot = options.repoRoot || DEFAULT_REPO_ROOT;

  const versionDir = join(versionedDocsDir, `version-${version}`);
  if (!pathExists(versionDir)) {
    throw new Error(`regenerate-versioned-reference: version '${version}' does not exist at ${versionDir}`);
  }
  if (!pathExists(referenceDir) || !pathExists(vocabDir)) {
    throw new Error(
      'regenerate-versioned-reference: generated references/vocabulary are missing. Run `npm run generate` first.',
    );
  }
  const targetReferenceDir = join(versionDir, 'reference');
  if (!pathExists(targetReferenceDir)) {
    throw new Error(`regenerate-versioned-reference: no existing reference/ subtree at ${targetReferenceDir}`);
  }

  const vocabSets = loadSets(vocabDir);
  const allowBases = includeAllowBases(repoRoot);
  const sourceRelPaths = listFiles(referenceDir).filter((rel) => rel.endsWith('.mdx') || rel.endsWith('.md'));

  const stagingDir = mkdtempSync(join(versionDir, STAGING_DIR_PREFIX));
  try {
    for (const rel of sourceRelPaths) {
      const source = readFileSync(join(referenceDir, rel), 'utf8');
      const out = dematerialize(source, {
        version,
        repoRoot,
        allowBases,
        vocabSets,
        docLabel: rel,
      });
      const target = join(stagingDir, rel);
      mkdirSync(dirname(target), {recursive: true});
      writeFileSync(target, out, 'utf8');
    }
    // Every page succeeded — only now does the real target subtree get touched. `reference/` is
    // removed and the fully-regenerated staging directory renamed into its place, so the target
    // ends up holding EXACTLY the current generated inventory: no stale renamed/deleted page and
    // no stale now-empty directory can survive, and nothing outside `reference/` in this version
    // (or any other version) is ever touched.
    rmSync(targetReferenceDir, {recursive: true, force: true});
    renameSync(stagingDir, targetReferenceDir);
  } catch (err) {
    rmSync(stagingDir, {recursive: true, force: true});
    throw err;
  }
  console.log(
    `[regenerate-versioned-reference] regenerated ${sourceRelPaths.length} reference page(s) for version ` +
      `'${version}' at ${targetReferenceDir}`,
  );
  return sourceRelPaths.length;
}

// CLI entry.
if (process.argv[1]?.endsWith('regenerate-versioned-reference.mjs')) {
  const version = process.argv[2];
  if (!version) {
    console.error('Usage: node scripts/regenerate-versioned-reference.mjs <version>');
    process.exit(1);
  }
  regenerateVersionedReference(version);
}
